import{_ as r,o as a,c as e,a2 as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-06-02.md","filePath":"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-06-02.md"}'),n={name:"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-06-02.md"};function i(d,t,l,s,h,p){return a(),e("div",null,[...t[0]||(t[0]=[o('<p>💡 光通訊追蹤日報 — 2026年6月2日（週二）</p><blockquote><p><strong>查詢時間</strong>：TST 05:00 (2026-06-02 05:00 = 2026-06-01 21:00 UTC) <strong>昨日敘事延續</strong>：NVIDIA Computex RTX Spark + Vera Rubin + $40 億光子投資 + Anthropic IPO + COMPUTEX 今日正式開幕 + 光通訊族群強勢</p></blockquote><hr><h2 id="🔴-即時指標-每日掃描" tabindex="-1">🔴 即時指標（每日掃描） <a class="header-anchor" href="#🔴-即時指標-每日掃描" aria-label="Permalink to &quot;🔴 即時指標（每日掃描）&quot;">​</a></h2><h3 id="指標1️⃣-輝達-nvidia-—-🔴-computex-重磅發表-rtx-spark-vera-rubin-光子生態系" tabindex="-1">指標1️⃣ 輝達 NVIDIA — 🔴 Computex 重磅發表：RTX Spark + Vera Rubin + 光子生態系 <a class="header-anchor" href="#指標1️⃣-輝達-nvidia-—-🔴-computex-重磅發表-rtx-spark-vera-rubin-光子生態系" aria-label="Permalink to &quot;指標1️⃣ 輝達 NVIDIA — 🔴 Computex 重磅發表：RTX Spark + Vera Rubin + 光子生態系&quot;">​</a></h3><p><strong>6/1 GTC Taipei 發表</strong>：</p><ul><li><strong>RTX Spark</strong>：首款 Windows on Arm PC 晶片平台，搭載 GB10 Grace Blackwell 超級晶片，與聯發科合作 <ul><li>黃仁勳：「電腦的重新發明，如同手機變成了智慧型手機」</li><li>AI 將在所有新電腦上運行</li></ul></li><li><strong>Vera Rubin 架構</strong>：Vera CPU + Rubin GPU，機櫃級超級電腦，宣稱 10 年 4,000 萬倍算力提升</li><li><strong>NVIDIA 光子投資 $40 億</strong>： <ul><li>Coherent：$20 億（取得雷射元件優先使用權）</li><li>Lumentum：$20 億（取得雷射元件優先使用權）</li></ul></li><li><strong>Spectrum-X Ethernet Photonics</strong>：409.6 Tb/s，<strong>2026 下半年上市</strong></li><li><strong>NVIDIA 計畫每年在台灣投資 ~$1,500 億</strong>，2030 前建立台灣總部</li><li><strong>DGX Station for Windows</strong>：搭載 GB10 Grace Blackwell，萬億參數 AI 能力</li><li><strong>Cosmos 3</strong>：開源 AI 模型，用於物理世界應用</li><li><strong>Isaac GR00T</strong>：人形機器人參考平台</li><li><strong>SMCI</strong>：為 NVIDIA Vera Rubin 平台推出資料中心設計方案</li></ul><p><strong>合作夥伴生態系</strong>：</p><ul><li>Coherent、Lumentum、Corning、Ayar Labs、Marvell、TSMC、Ayar Labs、Global Unichip (GUC)</li><li>Wiwynn + 生態系夥伴（Ayar Labs、GUC、Browave、Corning、FOCI、Molex、SENKO、TE）在 COMPUTEX 展示 CPO 互連技術</li></ul><p><strong>技術路線圖</strong>：</p><ul><li>2026：CPO 交換器小規模試產（Scale-out），機櫃內部仍以銅纜為主（Scale-up）</li><li>2027+：CPO 真正爆發</li><li>Feynman 架構：矽光子整合至晶片內部</li></ul><p><strong>6/1 NVIDIA 股價</strong>：$211.14（-1.45%），預盤 +2.1%</p><p><strong>評估</strong>：COMPUTEX 2026 今日正式開幕（6/2-5），NVIDIA 發表的 RTX Spark + Vera Rubin + $40 億光子投資是本週最大催化劑。光通訊族群有望延續強勢。</p><p>📎 來源：<a href="https://www.nvidia.com/en-tw/gtc/taipei/computex/" target="_blank" rel="noreferrer">NVIDIA</a> · <a href="https://www.pcmag.com/news/live-from-computex-2026-were-in-taipei-bringing-you-every-big-pc-reveal" target="_blank" rel="noreferrer">PCMag</a> · <a href="https://siliconangle.com/2026/06/01/nvidia-ramps-production-vera-rubin-foundation-next-generation-ai-factories/" target="_blank" rel="noreferrer">SiliconAngle</a> · <a href="https://www.tomshardware.com/news/live/computex-2026-" target="_blank" rel="noreferrer">Tom&#39;s Hardware</a> （TST 05:00）</p><hr><h3 id="指標2️⃣-博通-broadcom-—-🟡-cpo-路線圖持續-computex-有新展示" tabindex="-1">指標2️⃣ 博通 Broadcom — 🟡 CPO 路線圖持續，COMPUTEX 有新展示 <a class="header-anchor" href="#指標2️⃣-博通-broadcom-—-🟡-cpo-路線圖持續-computex-有新展示" aria-label="Permalink to &quot;指標2️⃣ 博通 Broadcom — 🟡 CPO 路線圖持續，COMPUTEX 有新展示&quot;">​</a></h3><p><strong>最新動態</strong>：</p><ul><li>博通在交換器 ASIC 路線圖中明確列出 CPO 版本</li><li>與 NVIDIA 在 CPO 標準上既有競爭也有合作</li><li>2026 年被視為 CPO「商轉元年」，博通是關鍵玩家之一</li><li><strong>COMPUTEX 2026</strong>：博通預計展示最新 CPO/DSP 產品</li><li><strong>Wiwynn + Ayar Labs + 博通生態系</strong>：在 COMPUTEX 展示全棧 CPO 互連技術（從晶片級到資料中心規模）</li></ul><p><strong>評估</strong>：博通 CPO 策略持續推進，COMPUTEX 期間可能有新披露。等待展會期間進一步消息。</p><p>📎 來源：<a href="https://www.digitimes.com/news/a20260527PD211/ezconn-cpo-siph-2026.html" target="_blank" rel="noreferrer">DigiTimes</a> · <a href="https://www.wiwynn.com/news/wiwynn-and-ecosystem-partners-to-showcase-co-packaged-optics-innovations-at-computex-2026" target="_blank" rel="noreferrer">Wiwynn PR</a> （TST 05:00）</p><hr><h3 id="指標3️⃣-台積電-tsmc-—-🟢-coupe-進展穩定-computex-核心供應商" tabindex="-1">指標3️⃣ 台積電 TSMC — 🟢 COUPE 進展穩定 + COMPUTEX 核心供應商 <a class="header-anchor" href="#指標3️⃣-台積電-tsmc-—-🟢-coupe-進展穩定-computex-核心供應商" aria-label="Permalink to &quot;指標3️⃣ 台積電 TSMC — 🟢 COUPE 進展穩定 + COMPUTEX 核心供應商&quot;">​</a></h3><p><strong>最新動態</strong>：</p><ul><li>台積電 COUPE 技術已進入小批量產階段</li><li>與 NVIDIA 合作：將光子技術整合至 GPU 互連系統</li><li>CoWoS 產能持續擴張以滿足 AI 晶片需求</li><li>台積電（2330）5/29 盤中最高 2,360 元新天價，盤後鉅額交易出現 2,442 元新高價</li><li><strong>魏哲家</strong>：員工分紅增幅至少不低於去年（30%），鼓勵員工買進台積電股票</li><li><strong>大摩 COMPUTEX 報告</strong>：台積電為核心供應鏈，目標價維持</li><li><strong>台灣市值</strong>：已躍升全球第五大，81.44% 集中在科技相關產業</li></ul><p><strong>評估</strong>：台積電先進封裝技術是 CPO 量產的關鍵基礎設施，COUPE 進展穩定。</p><p>📎 來源：<a href="https://news.cnyes.com/news/id/6471653" target="_blank" rel="noreferrer">鉅亨網</a> · <a href="https://www.cna.com.tw/news/afe/202605280356.aspx" target="_blank" rel="noreferrer">CNA</a> · <a href="https://www.nvidia.com/en-tw/gtc/taipei/computex/" target="_blank" rel="noreferrer">NVIDIA</a> （TST 05:00）</p><hr><h3 id="指標4️⃣-csp-資本支出-—-🟡-ai-capex-持續擴張" tabindex="-1">指標4️⃣ CSP 資本支出 — 🟡 AI capex 持續擴張 <a class="header-anchor" href="#指標4️⃣-csp-資本支出-—-🟡-ai-capex-持續擴張" aria-label="Permalink to &quot;指標4️⃣ CSP 資本支出 — 🟡 AI capex 持續擴張&quot;">​</a></h3><p><strong>最新動態</strong>：</p><ul><li><strong>Anthropic 秘密提交 IPO</strong>：融資 $650 億，估值 $9,650 億 → AI 投資热潮持續</li><li><strong>SoftBank +14%</strong>（6/1 東京）→ AI 基礎設施投資持續</li><li><strong>南韓 Kospi +109% YTD</strong>：AI 晶片股主導</li><li><strong>Fundstrat Tom Lee</strong>：「2026 年後可能看到我們一生中最大的股市漲幅」</li><li><strong>微軟、Google、Amazon、Meta</strong>：AI capex 2026 預計持續成長</li><li>CPO 市場預測：IDTechEx 預計 2036 年超 $200 億，CAGR 37%（2026-2036）</li></ul><p><strong>與昨日比較</strong>：Anthropic IPO 是新催化劑，顯示 AI 投資热潮未減。</p><p>📎 來源：<a href="https://www.theguardian.com/technology/2026/jun/01/anthropic-ai-ipo" target="_blank" rel="noreferrer">Guardian</a> · <a href="https://www.forbes.com/sites/aliciapark/2026/06/01/anthropic-confidentially-files-for-its-highly-anticipated-ipo/" target="_blank" rel="noreferrer">Forbes</a> · <a href="https://blogs.sw.siemens.com/semiconductor-packaging/2026/02/05/five-key-trends-of-co-packaged-optics-cpo-in-2026/" target="_blank" rel="noreferrer">IDTechEx via Siemens</a> （TST 05:00）</p><hr><h2 id="🟡-台灣光通訊供應鏈" tabindex="-1">🟡 台灣光通訊供應鏈 <a class="header-anchor" href="#🟡-台灣光通訊供應鏈" aria-label="Permalink to &quot;🟡 台灣光通訊供應鏈&quot;">​</a></h2><table tabindex="0"><thead><tr><th>公司</th><th>代號</th><th>COMPUTEX 動態</th><th>評估</th></tr></thead><tbody><tr><td>聯亞</td><td>3081</td><td>無個股特定新聞</td><td>本日無個股更新</td></tr><tr><td>光聖</td><td>6442</td><td>無個股特定新聞</td><td>本日無個股更新</td></tr><tr><td>上詮</td><td>3363</td><td>無個股特定新聞</td><td>本日無個股更新</td></tr><tr><td>智邦</td><td>2345</td><td>無個股特定新聞</td><td>本日無個股更新</td></tr><tr><td>波若威</td><td>3163</td><td>5/25 漲停（COMPUTEX 催動）</td><td>延續強勢</td></tr><tr><td>前鼎</td><td>—</td><td>5/25 漲停</td><td>延續強勢</td></tr></tbody></table><p><strong>5/25 漲停族羣回顧</strong>：波若威、光聖、聯亞、前鼎 4 檔漲停，受 NVIDIA 光子投資 + COMPUTEX 催動。</p><p><strong>大摩 COMPUTEX 報告點名</strong>：台積電、聯電、京元電、日月光、鴻海等 9 檔。</p><p>📎 來源：<a href="https://news.cnyes.com/news/id/6469850" target="_blank" rel="noreferrer">鉅亨網</a> （TST 05:00）</p><hr><h2 id="🔵-月度指標-6月更新" tabindex="-1">🔵 月度指標（6月更新） <a class="header-anchor" href="#🔵-月度指標-6月更新" aria-label="Permalink to &quot;🔵 月度指標（6月更新）&quot;">​</a></h2><h3 id="m1-m3-月度指標" tabindex="-1">M1-M3 月度指標 <a class="header-anchor" href="#m1-m3-月度指標" aria-label="Permalink to &quot;M1-M3 月度指標&quot;">​</a></h3><ul><li><strong>800G 光收發模組出貨量</strong>：待 6 月中旬更新</li><li><strong>1.6T 光收發模組出貨量</strong>：待 6 月中旬更新</li><li><strong>InP 基板價格走勢</strong>：待 6 月中旬更新</li></ul><p><strong>評估</strong>：月度指標通常在月中更新，本週 COMPUTEX 可能帶來新的產業數據。</p><hr><h2 id="🟢-法說會指標" tabindex="-1">🟢 法說會指標 <a class="header-anchor" href="#🟢-法說會指標" aria-label="Permalink to &quot;🟢 法說會指標&quot;">​</a></h2><ul><li><strong>聯亞 3081</strong>：待下次法說會</li><li><strong>全新 2455</strong>：待下次法說會</li><li><strong>英特磊 4971</strong>：待下次法說會</li><li><strong>光聖 6442</strong>：待下次法說會</li><li><strong>波若威 3163</strong>：待下次法說會</li></ul><p><strong>評估</strong>：COMPUTEX 期間可能有法說會或產業論壇，持續追蹤。</p><hr><h2 id="📊-產業趨勢摘要" tabindex="-1">📊 產業趨勢摘要 <a class="header-anchor" href="#📊-產業趨勢摘要" aria-label="Permalink to &quot;📊 產業趨勢摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>趨勢</th><th>狀態</th><th>說明</th></tr></thead><tbody><tr><td>銅退光進</td><td>🟢 加速</td><td>NVIDIA $40 億光子投資 + Spectrum-X 2026H2 上市</td></tr><tr><td>2026 商轉元年</td><td>🟢 進行中</td><td>CPO 小規模試產，2027+ 真正爆發</td></tr><tr><td>OCI-MSA 標準</td><td>🟡 推進中</td><td>行業標準制定持續</td></tr><tr><td>AI capex 擴張</td><td>🟢 強勁</td><td>Anthropic IPO + SoftBank +14% + Kospi +109% YTD</td></tr><tr><td>COMPUTEX 2026</td><td>🔴 本週</td><td>6/2-5 台北，NVIDIA 核心角色</td></tr></tbody></table><hr><h2 id="📰-即時新聞-5條" tabindex="-1">📰 即時新聞（5條） <a class="header-anchor" href="#📰-即時新聞-5條" aria-label="Permalink to &quot;📰 即時新聞（5條）&quot;">​</a></h2><h3 id="_1-🔴-nvidia-computex-rtx-spark-vera-rubin-40-億光子投資" tabindex="-1">1. 🔴 NVIDIA Computex RTX Spark + Vera Rubin + $40 億光子投資 <a class="header-anchor" href="#_1-🔴-nvidia-computex-rtx-spark-vera-rubin-40-億光子投資" aria-label="Permalink to &quot;1. 🔴 NVIDIA Computex RTX Spark + Vera Rubin + $40 億光子投資&quot;">​</a></h3><p>黃仁勳 GTC Taipei 發表首款 Windows PC 晶片 RTX Spark、Vera Rubin 架構、$40 億光子投資（Coherent + Lumentum 各 $20 億）、Spectrum-X 409.6 Tb/s 2026H2 上市。COMPUTEX 今日開幕。（來源：NVIDIA、SiliconAngle，TST 05:00）</p><h3 id="_2-🔴-anthropic-秘密提交-ipo-估值-9-650-億超越-openai" tabindex="-1">2. 🔴 Anthropic 秘密提交 IPO，估值 $9,650 億超越 OpenAI <a class="header-anchor" href="#_2-🔴-anthropic-秘密提交-ipo-估值-9-650-億超越-openai" aria-label="Permalink to &quot;2. 🔴 Anthropic 秘密提交 IPO，估值 $9,650 億超越 OpenAI&quot;">​</a></h3><p>Anthropic 6/1 正式向 SEC 秘密提交 IPO 文件。此前融資 $650 億，估值 $9,650 億。AI 產業 IPO 熱潮啟動，CSP 資本支出預期進一步上升。（來源：Guardian、Forbes、Crunchbase，TST 05:00）</p><h3 id="_3-🟡-wiwynn-生態系夥伴-computex-展示全棧-cpo-互連技術" tabindex="-1">3. 🟡 Wiwynn + 生態系夥伴 COMPUTEX 展示全棧 CPO 互連技術 <a class="header-anchor" href="#_3-🟡-wiwynn-生態系夥伴-computex-展示全棧-cpo-互連技術" aria-label="Permalink to &quot;3. 🟡 Wiwynn + 生態系夥伴 COMPUTEX 展示全棧 CPO 互連技術&quot;">​</a></h3><p>Wiwynn 與 Ayar Labs、GUC、Corning、FOCI、Molex、SENKO、TE 等夥伴在 COMPUTEX 2026 展示從晶片級 CPO 到資料中心規模的全棧互連技術。（來源：Wiwynn PR、PRNewswire，TST 05:00）</p><h3 id="_4-🟡-authenx-computex-展示可拆卸-2d-fau-技術" tabindex="-1">4. 🟡 AuthenX COMPUTEX 展示可拆卸 2D FAU 技術 <a class="header-anchor" href="#_4-🟡-authenx-computex-展示可拆卸-2d-fau-技術" aria-label="Permalink to &quot;4. 🟡 AuthenX COMPUTEX 展示可拆卸 2D FAU 技術&quot;">​</a></h3><p>AuthenX 將展示可拆卸 2D 光纖陣列單元（FAU）技術，整合 12 吋 CMOS 超透鏡，解決光學封裝瓶頸，支援 3.2T 至 12.8T CPO 架構。（來源：Morningstar/PRNewswire，TST 05:00）</p><h3 id="_5-🟡-台股-45-337-歷史新高-ai-computex-催動" tabindex="-1">5. 🟡 台股 45,337 歷史新高，AI + COMPUTEX 催動 <a class="header-anchor" href="#_5-🟡-台股-45-337-歷史新高-ai-computex-催動" aria-label="Permalink to &quot;5. 🟡 台股 45,337 歷史新高，AI + COMPUTEX 催動&quot;">​</a></h3><p>TAIEX 45,337.91（+1.35%），首度站上 45,000。成交值 NT$1.48 兆。NVIDIA Computex + AI 熱潮驅動科技股全面走強。（來源：TaiwanNews、FocusTaiwan，TST 05:00）</p><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>來源</th><th>查詢時間</th><th>內容</th></tr></thead><tbody><tr><td>1</td><td>NVIDIA 官網</td><td>TST 05:00</td><td>Computex GTC Taipei 發表</td></tr><tr><td>2</td><td>SiliconAngle</td><td>TST 05:00</td><td>Vera Rubin 量產</td></tr><tr><td>3</td><td>PCMag</td><td>TST 05:00</td><td>Computex 現場報導</td></tr><tr><td>4</td><td>Tom&#39;s Hardware</td><td>TST 05:00</td><td>Computex 即時更新</td></tr><tr><td>5</td><td>Wiwynn PR</td><td>TST 05:00</td><td>CPO 生態系展示</td></tr><tr><td>6</td><td>AuthenX/Morningstar</td><td>TST 05:00</td><td>2D FAU 技術</td></tr><tr><td>7</td><td>Guardian</td><td>TST 05:00</td><td>Anthropic IPO</td></tr><tr><td>8</td><td>Forbes</td><td>TST 05:00</td><td>Anthropic IPO</td></tr><tr><td>9</td><td>Siemens Blog</td><td>TST 05:00</td><td>CPO 五大趨勢</td></tr><tr><td>10</td><td>TaiwanNews</td><td>TST 05:00</td><td>台股收盤</td></tr><tr><td>11</td><td>鉅亨網</td><td>TST 05:00</td><td>NVIDIA 光子投資</td></tr><tr><td>12</td><td>DigiTimes</td><td>TST 05:00</td><td>博通 CPO 路線圖</td></tr></tbody></table>',65)])])}const g=r(n,[["render",i]]);export{u as __pageData,g as default};
